import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast } from 'react-toastify';

const CATEGORIES = ['Technology', 'Health', 'Education', 'Environment', 'Art', 'Social Impact', 'Finance', 'Other'];

export default function SubmitProject() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    title: '', description: '', category: 'Technology',
    fundingGoal: '', teamSize: '', timeline: '', coverImage: '', deadline: ''
  });

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (form.description.length < 50) {
      return toast.error('Description must be at least 50 characters');
    }
    setLoading(true);
    try {
      await axios.post('/api/projects', {
        ...form,
        fundingGoal: Number(form.fundingGoal),
        teamSize: Number(form.teamSize)
      });
      toast.success('🚀 Project submitted! AI evaluation in progress...');
      navigate('/innovator');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Submission failed');
    } finally {
      setLoading(false);
    }
  };

  const inputClass = "w-full px-4 py-3 rounded-xl text-sm focus:outline-none transition-colors";
  const inputStyle = { background: '#0a0d1a', border: '1px solid #374151', color: 'white' };

  return (
    <div style={{ background: '#0a0d1a', minHeight: '100vh' }} className="px-6 py-10">
      <div className="max-w-2xl mx-auto">
        <div className="mb-10">
          <h1 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold mb-2">Submit a Project</h1>
          <p className="text-gray-400">Fill in the details below. Google Gemini AI will evaluate your project automatically.</p>
        </div>

        <div style={{ background: 'rgba(0,212,170,0.05)', border: '1px solid rgba(0,212,170,0.2)' }}
             className="rounded-xl p-4 mb-8 flex items-start gap-3">
          <span className="text-xl">✦</span>
          <div>
            <p style={{ color: '#00d4aa' }} className="text-sm font-semibold">AI-Powered Evaluation</p>
            <p className="text-gray-400 text-sm mt-0.5">After submission, Gemini AI will score your project on feasibility and success probability to assist admin review.</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-sm text-gray-400 mb-1.5">Project Title *</label>
            <input name="title" value={form.title} onChange={handleChange} required minLength={5} maxLength={120}
              className={inputClass} style={inputStyle} placeholder="An inspiring project title..." />
          </div>

          <div>
            <label className="block text-sm text-gray-400 mb-1.5">Description * (min 50 chars)</label>
            <textarea name="description" value={form.description} onChange={handleChange} required
              rows={5} className={inputClass} style={inputStyle}
              placeholder="Describe your project, its goals, impact, and why it deserves funding..." />
            <div className="text-right text-xs text-gray-600 mt-1">{form.description.length} chars</div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm text-gray-400 mb-1.5">Category *</label>
              <select name="category" value={form.category} onChange={handleChange}
                className={inputClass} style={inputStyle}>
                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm text-gray-400 mb-1.5">Funding Goal ($) *</label>
              <input name="fundingGoal" type="number" value={form.fundingGoal} onChange={handleChange} required min={100}
                className={inputClass} style={inputStyle} placeholder="e.g. 50000" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm text-gray-400 mb-1.5">Team Size *</label>
              <input name="teamSize" type="number" value={form.teamSize} onChange={handleChange} required min={1}
                className={inputClass} style={inputStyle} placeholder="e.g. 4" />
            </div>
            <div>
              <label className="block text-sm text-gray-400 mb-1.5">Timeline *</label>
              <input name="timeline" value={form.timeline} onChange={handleChange} required
                className={inputClass} style={inputStyle} placeholder="e.g. 12 months" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm text-gray-400 mb-1.5">Cover Image URL</label>
              <input name="coverImage" value={form.coverImage} onChange={handleChange}
                className={inputClass} style={inputStyle} placeholder="https://..." />
            </div>
            <div>
              <label className="block text-sm text-gray-400 mb-1.5">Campaign Deadline</label>
              <input name="deadline" type="date" value={form.deadline} onChange={handleChange}
                className={inputClass} style={inputStyle} />
            </div>
          </div>

          <button type="submit" disabled={loading}
            style={{ background: '#00d4aa', color: '#0a0d1a' }}
            className="w-full py-3.5 rounded-xl font-bold text-sm hover:opacity-90 transition-all disabled:opacity-60 mt-2">
            {loading ? 'Submitting...' : '🚀 Submit Project for AI Evaluation'}
          </button>
        </form>
      </div>
    </div>
  );
}
